objects.draw:
function(ctx, obj) {
\
        ctx.save();
\

\
        const r = obj.radius;
\

\
        // === ROLDANA ===
\
        ctx.beginPath();
\
        ctx.arc(obj.x, obj.y, r, 0, Math.PI * 2);
\
        ctx.fillStyle = '#94a3b8';
\
        ctx.fill();
\
        ctx.strokeStyle = '#475569';
\
        ctx.lineWidth = 2;
\
        ctx.stroke();
\

\
        // eixo
\
        ctx.beginPath();
\
        ctx.arc(obj.x, obj.y, r * 0.2, 0, Math.PI * 2);
\
        ctx.fillStyle = '#0f172a';
\
        ctx.fill();
\

\
        // === CORDA CONTÍNUA ===
\
        const leftX = obj.x - r;
\
        const rightX = obj.x + r;
\

\
        ctx.beginPath();
\

\
        // lado esquerdo (vertical)
\
        ctx.moveTo(leftX, obj.y);
\
        ctx.lineTo(leftX, obj.leftY);
\

\
        // conexão com massa esquerda
\
        if (obj.leftMassObj) {
\
          ctx.lineTo(obj.leftMassObj.x, obj.leftMassObj.y - obj.leftMassObj.w);
\
        }
\

\
        // voltar para roldana
\
        ctx.moveTo(rightX, obj.y);
\

\
        // lado direito (vertical)
\
        ctx.lineTo(rightX, obj.rightY);
\

\
        // conexão massa direita
\
        if (obj.rightMassObj) {
\
          ctx.lineTo(obj.rightMassObj.x, obj.rightMassObj.y - obj.rightMassObj.w);
\
        }
\

\
        ctx.strokeStyle = obj.ropeColor;
\
        ctx.lineWidth = obj.ropeWidth;
\
        ctx.stroke();
\

\
        ctx.restore();
\
      }

objects.update:
function(obj, dt) {
\
        if (!obj.leftMassObj || !obj.rightMassObj) return;
\

\
        const m1 = obj.leftMassObj.mass;
\
        const m2 = obj.rightMassObj.mass;
\
        const g = Lab.state.gravity;
\
        const r = obj.radius / 100;
\
        const I = obj.momentOfInertia;
\

\
        // === ACELERAÇÃO ===
\
        const a = (m2 - m1) * g / (m1 + m2 + I/(r*r));
\

\
        // === VELOCIDADE ===
\
        obj.velocity += a * dt;
\
        obj.velocity *= (1 - obj.friction);
\

\
        // === POSIÇÕES ===
\
        obj.leftY -= obj.velocity;
\
        obj.rightY += obj.velocity;
\

\
        // limites simples
\
        obj.leftY = Math.max(100, Math.min(500, obj.leftY));
\
        obj.rightY = Math.max(100, Math.min(500, obj.rightY));
\

\
        // === ATUALIZAR MASSAS ===
\
        obj.leftMassObj.x = obj.x - obj.radius;
\
        obj.rightMassObj.x = obj.x + obj.radius;
\

\
        obj.leftMassObj.y = obj.leftY;
\
        obj.rightMassObj.y = obj.rightY;
\

\
        // === ROTAÇÃO ===
\
        obj.angularVelocity = obj.velocity / r;
\
        obj.rotation += obj.angularVelocity * dt;
\
      }

objects.draw:
function(ctx, obj) {
\
        ctx.save();
\

\
        ctx.beginPath();
\
        ctx.arc(obj.x, obj.y, obj.w, 0, Math.PI * 2);
\
        ctx.fillStyle = obj.fill;
\
        ctx.fill();
\

\
        // gancho (onde a corda prende)
\
        ctx.beginPath();
\
        ctx.moveTo(obj.x, obj.y - obj.w);
\
        ctx.lineTo(obj.x, obj.y - obj.w - 10);
\
        ctx.strokeStyle = '#000';
\
        ctx.stroke();
\

\
        ctx.fillStyle = '#fff';
\
        ctx.font = '10px monospace';
\
        ctx.fillText(obj.mass + 'kg', obj.x - 12, obj.y + 3);
\

\
        ctx.restore();
\
      }
